+    if (AdbcStatementNew(m_connection.get(), statement.get(), error) !=
+        ADBC_STATUS_OK)
+    {
+        CPLError(CE_Failure, CPLE_AppDefined, "AdbcStatementNew() failed: %s",
+                 error.message());
+        return nullptr;
