+OGRADBCDataset::~OGRADBCDataset()
+{
+    // Layers must be closed before the connection
+    m_apoLayers.clear();
+    OGRADBCError error;
+    if (m_connection)
+        AdbcConnectionRelease(m_connection.get(), error);
+    error.clear();
+    AdbcDatabaseRelease(&m_database, error);
+}
