+    {
+        CPLError(CE_Failure, CPLE_AppDefined,
+                 "AdbcStatementExecuteQuery() failed: %s", error.message());
+        error.clear();
+        AdbcStatementRelease(statement.get(), error);
+        return nullptr;
+    }
+
+    ArrowSchema schema = {};
