+        CPLError(CE_Failure, CPLE_AppDefined, "get_schema() failed");
+        AdbcStatementRelease(statement.get(), error);
+        return nullptr;
+    }
+
+    return std::make_unique<OGRADBCLayer>(
+        this, pszLayerName, std::move(statement), std::move(stream), &schema);
