{"action":"created","issue":{"url":"https://api.github.com/repos/geopandas/geo-arrow-spec/issues/12","repository_url":"https://api.github.com/repos/geopandas/geo-arrow-spec","labels_url":"https://api.github.com/repos/geopandas/geo-arrow-spec/issues/12/labels{/name}","comments_url":"https://api.github.com/repos/geopandas/geo-arrow-spec/issues/12/comments","events_url":"https://api.github.com/repos/geopandas/geo-arrow-spec/issues/12/events","html_url":"https://github.com/geopandas/geo-arrow-spec/pull/12","id":1063617884,"node_id":"PR_kwDODx3ZIc4vBScF","number":12,"title":"First draft specification to store geometries in Arrow data as nested lists","user":{"login":"jorisvandenbossche","id":1020496,"node_id":"MDQ6VXNlcjEwMjA0OTY=","avatar_url":"https://avatars.githubusercontent.com/u/1020496?v=4","gravatar_id":"","url":"https://api.github.com/users/jorisvandenbossche","html_url":"https://github.com/jorisvandenbossche","followers_url":"https://api.github.com/users/jorisvandenbossche/followers","following_url":"https://api.github.com/users/jorisvandenbossche/following{/other_user}","gists_url":"https://api.github.com/users/jorisvandenbossche/gists{/gist_id}","starred_url":"https://api.github.com/users/jorisvandenbossche/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/jorisvandenbossche/subscriptions","organizations_url":"https://api.github.com/users/jorisvandenbossche/orgs","repos_url":"https://api.github.com/users/jorisvandenbossche/repos","events_url":"https://api.github.com/users/jorisvandenbossche/events{/privacy}","received_events_url":"https://api.github.com/users/jorisvandenbossche/received_events","type":"User","site_admin":false},"labels":[],"state":"open","locked":false,"assignee":null,"assignees":[],"milestone":null,"comments":4,"created_at":"2021-11-25T13:53:39Z","updated_at":"2022-01-08T01:18:58Z","closed_at":null,"author_association":"MEMBER","active_lock_reason":null,"draft":false,"pull_request":{"url":"https://api.github.com/repos